// Example: Buzzer Melody
// Play three notes using tone() on pin 8.

int buzzerPin = 8;

void setup() {
  pinMode(buzzerPin, OUTPUT);
}

void loop() {
  tone(buzzerPin, 262); // C4
  delay(500);
  tone(buzzerPin, 330); // E4
  delay(500);
  tone(buzzerPin, 392); // G4
  delay(500);
  noTone(buzzerPin);
  delay(1000);
}
